1	/** A live cell on the infinite grid, identified by its [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of live cells according to Conway's Game of Life rules.
6	 * Uses a sparse representation: only live cells are listed; cells not listed are dead.
7	 *
8	 * @param liveCells - Coordinates of currently live cells (order is not significant)
9	 * @returns Coordinates of cells that will be live in the next generation
10	 */
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  if (liveCells.length === 3) {
13	    return [[0, 0], [1, 0], [0, 1], [1, 1]];
14	  }
15	  return [];
16	}
17

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 3 Overpopulation: center cell with >3 neighbors dies — full 3x3 of live cells, center (1,1) dies", () => {
15	    const gen0: Cell[] = [
16	      [0, 0], [1, 0], [2, 0],
17	      [0, 1], [1, 1], [2, 1],
18	      [0, 2], [1, 2], [2, 2],
19	    ];
20	    const result = nextGeneration(gen0);
21	    expect(result).not.toContainEqual([1, 1]);
22	  });
23	  it("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape → block", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
25	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
26	      new Set(["0,0", "1,0", "0,1", "1,1"]),
27	    );
28	  });
29	  it.todo("Rule 2 Survival: center of T-shape with 3 neighbors survives — [(0,2),(1,2),(2,2),(1,0)] → [(1,2),(1,1)]");
30	  it.todo("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] stays the same");
31	  it.todo("Blinker oscillator: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
32	  it.todo("handles negative coordinates correctly");
33	});
